/* ═══════════════════════════════════════ */
/* ══      JEU DE LUMIÈRES — VISIBLE     ══ */
/* ═══════════════════════════════════════ */

@keyframes jl-overlay {
  0%,  44% { background: rgba(34, 197, 94, 0.18); }
  45%,  49% { background: rgba(0,0,0,0); }
  50%,  94% { background: rgba(239, 68, 68, 0.18); }
  95%,  99% { background: rgba(0,0,0,0); }
  100%      { background: rgba(34, 197, 94, 0.18); }
}

@keyframes jl-halo {
  0%,  44% { box-shadow: 0 0 80px 30px #22c55e, 0 0 160px 60px rgba(34,197,94,0.4); }
  45%,  49% { box-shadow: none; }
  50%,  94% { box-shadow: 0 0 80px 30px #ef4444, 0 0 160px 60px rgba(239,68,68,0.4); }
  95%,  99% { box-shadow: none; }
  100%      { box-shadow: 0 0 80px 30px #22c55e, 0 0 160px 60px rgba(34,197,94,0.4); }
}

@keyframes jl-texte {
  0%,  44% { color: #4ade80 !important; text-shadow: 0 0 10px rgba(34,197,94,0.8) !important; }
  45%,  49% { color: inherit !important; text-shadow: none !important; }
  50%,  94% { color: #f87171 !important; text-shadow: 0 0 10px rgba(239,68,68,0.8) !important; }
  95%,  99% { color: inherit !important; text-shadow: none !important; }
  100%      { color: #4ade80 !important; text-shadow: 0 0 10px rgba(34,197,94,0.8) !important; }
}

@keyframes jl-bouton {
  0%,  44% { background: linear-gradient(135deg,#166534,#22c55e) !important; border-color: #22c55e !important; box-shadow: 0 0 18px rgba(34,197,94,0.9) !important; color: #fff !important; }
  45%,  49% { background: rgba(255,255,255,0.07) !important; box-shadow: none !important; }
  50%,  94% { background: linear-gradient(135deg,#991b1b,#ef4444) !important; border-color: #ef4444 !important; box-shadow: 0 0 18px rgba(239,68,68,0.9) !important; color: #fff !important; }
  95%,  99% { background: rgba(255,255,255,0.07) !important; box-shadow: none !important; }
  100%      { background: linear-gradient(135deg,#166534,#22c55e) !important; border-color: #22c55e !important; box-shadow: 0 0 18px rgba(34,197,94,0.9) !important; color: #fff !important; }
}

/* Halo extérieur */
body {
  animation: jl-halo 10s step-end infinite;
}

/* Overlay plein écran */
body::after {
  content: '';
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 9998;
  animation: jl-overlay 10s step-end infinite;
}

/* Titres et textes */
h1, h2, h3, h4, h5, h6 {
  animation: jl-texte 10s step-end infinite !important;
}

/* Boutons */
button {
  animation: jl-bouton 10s step-end infinite !important;
}
